<script>
function showError(message){document.getElementById('tool-error-text').textContent=message;document.getElementById('tool-error').style.display='flex';document.getElementById('tool-result').classList.remove('show');}
function clearError(){document.getElementById('tool-error').style.display='none';}
function runTool(){const aporte=parseFloat(document.getElementById('inv-aporte').value);const taxa=parseFloat(document.getElementById('inv-taxa').value)/100;const meses=parseInt(document.getElementById('inv-meses').value,10);clearError();if(isNaN(aporte)||isNaN(taxa)||isNaN(meses)||aporte<0||taxa<0||meses<=0){showError('Preencha aporte, taxa e prazo com valores válidos.');return;}let saldo=0;for(let i=0;i<meses;i++){saldo=(saldo+aporte)*(1+taxa);}document.getElementById('inv-total').textContent='R$ '+fmtBRL(saldo);document.getElementById('inv-aplicado').textContent='R$ '+fmtBRL(aporte*meses);document.getElementById('tool-detail').textContent='Simulação com aporte fixo e rentabilidade mensal constante.';showResult('tool-result');}function clearTool(){['inv-aporte','inv-taxa','inv-meses'].forEach(id=>document.getElementById(id).value='');['inv-total','inv-aplicado'].forEach(id=>document.getElementById(id).textContent='-');document.getElementById('tool-detail').textContent='';document.getElementById('tool-result').classList.remove('show');clearError();}function copyTool(button){if(!document.getElementById('tool-result').classList.contains('show')){showError('Calcule o investimento antes de copiar o resultado.');return;}copyToClipboard('Valor acumulado: '+document.getElementById('inv-total').textContent,button);}
</script>
